"use client";

import {
  useRef,
  useLayoutEffect,
  type ReactNode,
  type HTMLAttributes,
  type MouseEvent,
  type SyntheticEvent,
  type Ref,
} from "react";
import { usePresence } from "@/hooks/use-presence";
import { composeRefs } from "@/lib/compose-refs";
import "./dialog.css";

export interface DialogShellProps
  extends Omit<HTMLAttributes<HTMLDialogElement>, "onClick"> {
  open: boolean;
  onBackdropClick?: (e: MouseEvent<HTMLDialogElement>) => void;
  onCancel?: (e: SyntheticEvent<HTMLDialogElement>) => void;
  onClose?: () => void;
  children: ReactNode;
  dialogRef?: Ref<HTMLDialogElement>;
}

export function DialogShell({
  open,
  onBackdropClick,
  onCancel,
  onClose,
  children,
  className,
  dialogRef: externalDialogRef,
  ...props
}: DialogShellProps) {
  const dialogRef = useRef<HTMLDialogElement>(null);
  const { present, onAnimationEnd } = usePresence({ open, ref: dialogRef });

  useLayoutEffect(() => {
    const dialog = dialogRef.current;
    if (dialog && !dialog.open) dialog.showModal();
  }, [present]);

  if (!present) return null;

  return (
    <dialog
      ref={externalDialogRef ? composeRefs(dialogRef, externalDialogRef) : dialogRef}
      data-state={open ? "open" : "closed"}
      className={className}
      onClick={(e: MouseEvent<HTMLDialogElement>) => {
        if (e.target === dialogRef.current) onBackdropClick?.(e);
      }}
      onCancel={(e) => {
        e.preventDefault();
        onCancel?.(e);
      }}
      onAnimationEnd={(e) => {
        if (e.target === dialogRef.current && !open) {
          dialogRef.current?.close();
          onClose?.();
        }
        onAnimationEnd(e);
      }}
      {...props}
    >
      {children}
    </dialog>
  );
}

@layer base {
  dialog {
    --dialog-duration: 0.15s;
    padding: 0;
    border: none;
    background: transparent;
    overflow: visible;
  }
}

@layer components {
  dialog::backdrop {
    background: rgba(0, 0, 0, 0.6);
    backdrop-filter: blur(4px);
  }

  dialog[data-state="open"]::backdrop {
    animation: backdrop-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"]::backdrop {
    animation: backdrop-out var(--dialog-duration) ease-in forwards;
  }

  dialog[data-state="open"] {
    animation: dialog-in var(--dialog-duration) ease-out;
  }

  dialog[data-state="closed"] {
    animation: dialog-out var(--dialog-duration) ease-in forwards;
  }

  body:has(dialog[open]) {
    overflow: hidden;
    scrollbar-gutter: stable;
  }
}

@keyframes dialog-in {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

@keyframes dialog-out {
  from { opacity: 1; transform: scale(1); }
  to { opacity: 0; transform: scale(0.95); }
}

@keyframes backdrop-in {
  from { opacity: 0; }
  to { opacity: 1; }
}

@keyframes backdrop-out {
  from { opacity: 1; }
  to { opacity: 0; }
}

@media (prefers-reduced-motion: reduce) {
  dialog,
  dialog::backdrop {
    animation-duration: 0.01s !important;
  }
}
